package main

// 3955. Valid Binary Strings With Cost Limit
// You are given two integers n and k.

// The cost of a binary string s is defined as the sum of all indices i (0-based) such that s[i] == '1'.

// A binary string is considered valid if:
//     1. It does not contain two consecutive '1' characters.
//     2. Its cost is less than or equal to k.

// Return a list of all valid binary strings of length n in any order.

// Example 1:
// Input: n = 3, k = 1
// Output: ["000","010","100"]
// Explanation:
// The binary strings of length 3 without consecutive '1' characters are:
// "000" : cost = 0
// "100" : cost = 0
// "010" : cost = 1
// "001" : cost = 2
// "101" : cost = 0 + 2 = 2
// Among these, the strings with cost less than or equal to k = 1 are "000", "010" and "100".
// Thus, the valid strings are ["000", "010", "100"].

// Example 2:
// Input: n = 1, k = 0
// Output: ["0","1"]
// Explanation:
// The valid binary strings of length 1 are "0" and "1".
// Thus the answer is ["0", "1"].

// Constraints:
//     1 <= n <= 12
//     0 <= k <= n * (n - 1) / 2

import "fmt"
import "strings"

func generateValidStrings(n int, k int) []string {
    res := []string{}
    total := 1 << n // 2 ^ n 种组合
    for i := 0; i < total; i++ {
        // 转换为二进制字符串，补前导0到长度n
        s := fmt.Sprintf("%0*b", n, i)
        // 条件1：不包含连续的11
        if strings.Contains(s, "11") {
            continue
        }
        // 计算所有1所在的下标之和
        sum := 0
        for index, c := range s {
            if c == '1' {
                sum += index
            }
        }
        // 条件2：下标和 <=k
        if sum <= k {
            res = append(res, s)
        }
    }
    return res
}

func generateValidStrings1(n int, k int) []string {
    res := []string{}
    s := make([]byte, n)
    var dfs func(pos int, cost int)
    dfs = func(pos int, cost int) {
        if cost > k {
            return
        }
        if pos == n {
            res = append(res, string(s))
            return
        }
        s[pos] = '0'
        dfs(pos + 1, cost)
        if pos == 0 || s[pos-1] == '0' {
            s[pos] = '1'
            dfs(pos + 1, cost + pos)
        }
    }
    dfs(0, 0)
    return res
}

